 97→      const code = typeof payload.code === "string" && payload.code.trim() ? payload.code.trim() : undefined;
 98→      return { message, code };
 99→    }
100→    return { message: fallback };
101→  }
102→  const text = await response.text().catch(() => "");
103→  return { message: sanitizeErrorMessage(text, fallback) };
